#include <stdio.h>
#include <stdlib.h>
#include <chrono>
#include <omp.h>

#define RADIUS 7
#define BLOCK_SIZE 256

void stencil_1d(const int *in, int *out, int length) {
  int total_threads = length;

  #pragma omp parallel for
  for (int block_idx = 0; block_idx < length / BLOCK_SIZE; ++block_idx) {
    int gindex_base = block_idx * BLOCK_SIZE;

    // Use a local array for the shared memory simulation
    // Size is BLOCK_SIZE + 2*RADIUS to handle boundaries
    int temp[BLOCK_SIZE + 2 * RADIUS];

    // Load main data
    for (int t = 0; t < BLOCK_SIZE; ++t) {
      int gindex = gindex_base + t;
      int lindex = t + RADIUS;
      if (gindex < length) {
        temp[lindex] = in[gindex];
      }
    }

    // Load boundary data (left and right)
    // Left boundary: handled by threads with threadIdx.x < RADIUS
    for (int t = 0; t < RADIUS; ++t) {
      int gindex = gindex_base + t;
      int lindex = t + RADIUS;

      // Left neighbor
      if (gindex < RADIUS) {
        temp[lindex - RADIUS] = 0;
      } else {
        temp[lindex - RADIUS] = in[gindex - RADIUS];
      }

      // Right neighbor (fetch from next block's start)
      int right_gindex = gindex + BLOCK_SIZE;
      if (right_gindex < length) {
        temp[lindex + BLOCK_SIZE] = in[right_gindex];
      } else {
        // If out of bounds, treat as 0 or ignore? 
        // Original CUDA code: temp[lindex + BLOCK_SIZE] = in[gindex + BLOCK_SIZE];
        // This assumes valid access or relies on padding. 
        // The host allocates pad_size = (length + RADIUS), so access up to length+RADIUS-1 is safe.
        // gindex + BLOCK_SIZE can be up to (length/BLOCK_SIZE - 1)*BLOCK_SIZE + RADIUS + BLOCK_SIZE
        // = length - BLOCK_SIZE + RADIUS + BLOCK_SIZE = length + RADIUS.
        // So it is safe if allocated with padding.
        temp[lindex + BLOCK_SIZE] = in[right_gindex];
      }
    }

    // Compute result
    for (int t = 0; t < BLOCK_SIZE; ++t) {
      int gindex = gindex_base + t;
      if (gindex >= length) continue;

      int lindex = t + RADIUS;
      int result = 0;
      for (int offset = -RADIUS; offset <= RADIUS; ++offset) {
        result += temp[lindex + offset];
      }
      out[gindex] = result;
    }
  }
}

int main(int argc, char* argv[]) {
  if (argc != 3) {
    printf("Usage: %s <length> <repeat>\n", argv[0]);
    printf("length is a multiple of %d\n", BLOCK_SIZE);
    return 1;
  }
  const int length = atoi(argv[1]);
  const int repeat = atoi(argv[2]);

  int size = length * sizeof(int);
  int pad_size = (length + RADIUS) * sizeof(int);

  int *a, *b;

  a = (int *)malloc(pad_size); 
  b = (int *)malloc(size);

  for (int i = 0; i < length+RADIUS; i++) a[i] = i;

  // No device pointers needed for OpenMP

  auto start = std::chrono::steady_clock::now();

  for (int i = 0; i < repeat; i++) {
    stencil_1d(a, b, length);
  }

  auto end = std::chrono::steady_clock::now();
  auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
  printf("Average kernel execution time: %f (s)\n", (time * 1e-9f) / repeat);

  // Verification
  bool ok = true;
  for (int i = 0; i < 2*RADIUS; i++) {
    int s = 0;
    for (int j = i; j <= i+2*RADIUS; j++)
      s += j < RADIUS ? 0 : (a[j] - RADIUS);
    if (s != b[i]) {
      printf("Error at %d: %d (host) != %d (device)\n", i, s, b[i]);
      ok = false;
      break;
    }
  }

  for (int i = 2*RADIUS; i < length; i++) {
    int s = 0;
    for (int j = i-RADIUS; j <= i+RADIUS; j++)
      s += a[j];
    if (s != b[i]) {
      printf("Error at %d: %d (host) != %d (device)\n", i, s, b[i]);
      ok = false;
      break;
    }
  }
  printf("%s\n", ok ? "PASS" : "FAIL");

  free(a);
  free(b); 

  return 0;
}
